const EmbeddedModelAsset* GetAmpModelAsset(const char* token)
{
  if (token == nullptr || *token == '\0')
    return nullptr;
  for (const auto* asset : kAmpAssets)
  {
    if (std::strcmp(asset->token, token) == 0)
      return asset;
  }
  return nullptr;
}

const EmbeddedModelAsset* GetStompModelAsset(const char* token)
{
  if (token == nullptr || *token == '\0')
    return nullptr;
  for (const auto* asset : kStompAssets)
  {
    if (std::strcmp(asset->token, token) == 0)
      return asset;
  }
  return nullptr;
}
